import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;
import java.util.*;

public class SolutionTest {

    @Test
    void classic() {
        String[] result = new Solution().bucketSortByLength(
            new String[]{"banana", "ok", "a", "no", "apple"}, 6);
        assertArrayEquals(new String[]{"a", "ok", "no", "apple", "banana"}, result);
    }

    @Test
    void stable_sameLength() {
        // "ok" appears before "no" in input; both length 2 ŌĆö stable sort must preserve that order
        String[] result = new Solution().bucketSortByLength(
            new String[]{"ok", "no", "a"}, 3);
        assertArrayEquals(new String[]{"a", "ok", "no"}, result);
    }

    @Test
    void singleWord() {
        String[] result = new Solution().bucketSortByLength(new String[]{"hi"}, 5);
        assertArrayEquals(new String[]{"hi"}, result);
    }

    @Test
    void empty() {
        String[] result = new Solution().bucketSortByLength(new String[]{}, 3);
        assertArrayEquals(new String[]{}, result);
    }

    @Test
    void allSameLength() {
        // every word goes into the same bucket; original order preserved
        String[] result = new Solution().bucketSortByLength(
            new String[]{"cat", "dog", "ant"}, 3);
        assertArrayEquals(new String[]{"cat", "dog", "ant"}, result);
    }

    @Test
    void alreadySortedByLength() {
        String[] result = new Solution().bucketSortByLength(
            new String[]{"a", "ab", "abc", "abcd"}, 4);
        assertArrayEquals(new String[]{"a", "ab","abc", "abcd"}, result);
    }

    @Test
    void longestFirst() {
        // input in reverse length order
        String[] result = new Solution().bucketSortByLength(
            new String[]{"abcde", "abcd", "abc", "ab", "a"}, 5);
        assertArrayEquals(new String[]{"a", "ab", "abc", "abcd", "abcde"}, result);
    }
}
